import React, { useState } from 'react';
import MenuIcon from '@mui/icons-material/Menu';
import DrawerMenu from '../components/DrawerMenu';
import ContestCard from '../components/ContestCard';
import ContestModal from '../components/ContestModal';
import SkillManager from '../components/SkillManager';
import Header from '../components/Header';
import dummyUsers from '../data/dummyUsers';

function Home() {
  const [modalOpen, setModalOpen] = useState(false);
  const [userSkills, setUserSkills] = useState(["React", "JavaScript"]);
  const [users] = useState(dummyUsers);
  const [matched, setMatched] = useState([]);
  const [feedbacks, setFeedbacks] = useState({});
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [openMenus, setOpenMenus] = useState({});

  const matchTeam = () => {
    const shuffled = [...users].sort(() => Math.random() - 0.5);
    setMatched([shuffled.slice(0, 5), shuffled.slice(5, 10)]);
  };

  const handleFeedback = (teamIndex, isPositive) => {
    setFeedbacks(prev => ({ ...prev, [teamIndex]: isPositive }));
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)',
      fontFamily: "'Noto Sans KR', 'Montserrat', Arial, sans-serif"
    }}>
      <Header onMenuOpen={() => setDrawerOpen(true)} />
      <DrawerMenu
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
        openMenus={openMenus}
        onToggle={setOpenMenus}
      />

      <main style={{
        maxWidth: '1200px',
        margin: '3rem auto',
        padding: '0 2rem',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        textAlign: 'center'
      }}>
        <h2 style={{
          fontSize: '2.5rem',
          marginBottom: '1.5rem',
          color: '#222',
          fontWeight: 800,
          letterSpacing: '0.01em'
        }}>
          함께할 <span style={{ color: '#FF6B35' }}>팀원</span>이 필요하신가요?
        </h2>
        <p style={{
          fontSize: '1.1rem',
          color: '#555',
          marginBottom: '3rem'
        }}>
          <span style={{ color: '#FF6B35', fontWeight: 600 }}>TUP!</span>은 공모전 참가자들을 위한 지능형 팀 매칭 플랫폼입니다.<br />
          기술 스택과 관심사를 기반으로 최적의 팀원을 찾아보세요!
        </p>

        <ContestCard onClick={() => setModalOpen(true)} />

        <div style={{
          marginTop: '3rem',
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
          gap: '1.5rem'
        }}>
          <div style={{
            background: 'white',
            padding: '1.5rem',
            borderRadius: '12px',
            boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
            textAlign: 'center'
          }}>
            <h3 style={{ marginBottom: '0.5rem' }}>스킬 기반 매칭</h3>
            <p style={{ color: '#666' }}>기술 스택, 관심사, 경험을 기반으로 최적의 팀원을 찾습니다</p>
          </div>
          <div style={{
            background: 'white',
            padding: '1.5rem',
            borderRadius: '12px',
            boxShadow: '0 4px 15px rgba(0,0,0,0.1)',
            textAlign: 'center'
          }}>
            <h3 style={{ marginBottom: '0.5rem' }}>공모전 탐색</h3>
            <p style={{ color: '#666' }}>다양한 공모전 정보를 확인하고 팀을 바로 구성하세요</p>
          </div>
        </div>
      </main>

      <ContestModal
        open={modalOpen}
        onClose={() => setModalOpen(false)}
        users={users}
        userSkills={userSkills}
        setUserSkills={setUserSkills}
        matched={matched}
        matchTeam={matchTeam}
        feedbacks={feedbacks}
        onFeedback={handleFeedback}
      />
    </div>
  );
}

export default Home;
